// Filtert die breit gelesene Data Table auf die Ziel-Status des Visual
// Prompt Builders. Die Data Table kann kein OR über mehrere Werte desselben
// Feldes - deshalb wird hier gefiltert statt in der DB-Abfrage direkt
// (siehe "Hole needs_visual_prompt", vorher AND-verknüpfte Bedingungen == 0 Treffer).
// 'headline_selected' = Nutzer hat per Matrix-Antwort eine Headline/Subline-Variante
// gewählt; für diese Zeilen wird nur noch der Bildprompt gebaut, keine neuen
// Headline-Varianten mehr erzeugt (siehe "IF Headline bereits gewählt?").
const ZIEL_STATUS = ['needs_visual_prompt', 'headline_selected', 'visual_prompt_error', 'visual_prompt_topic_error', 'force_visual_reset'];
const ZIEL_STAGE = ['needs_prompt', 'headline_selected', 'prompt_error'];

return items.filter(item => {
  const vStage = String(item.json.visualStage || '').trim();
  if (vStage) return ZIEL_STAGE.includes(vStage);
  return ZIEL_STATUS.includes(String(item.json.visualStatus || '').trim());
});

// ============================================================
// PREPARE VISUAL PROMPT INPUT  (v2 — visual anchor fields)
// Übergibt alle Themenanker-Felder an die KI
// ============================================================

const raw = $input.item.json || {};

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function safeJson(v, fallback = '{}') {
  if (!v) return fallback;
  if (typeof v === 'string') return v.trim() || fallback;
  try { return JSON.stringify(v); } catch (e) { return fallback; }
}

function parseObject(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const parsed = JSON.parse(String(v));
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
  } catch (e) {
    return {};
  }
}

function firstValue(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;
    if (Array.isArray(value) && value.length > 0) return value;
    if (typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length > 0) return value;
    if (String(value).trim() !== '') return value;
  }
  return '';
}

// Die bestehenden Tabellenspalten bleiben unverändert.
// Detailfelder werden aus analysisJson bzw. visualJson.anchors gelesen.
const analysis = parseObject(raw.analysisJson);
const storedVisual = parseObject(raw.visualJson);
const storedAnchors = parseObject(storedVisual.anchors);
const analysisAnchors = parseObject(analysis.visualAnchors);

// ============================================================
// SOURCELOCK aus analysisJson extrahieren (hat Vorrang vor visualJson)
// ============================================================
const sourceLockFromAnalysis = parseObject(analysis.sourceLock || {});
const storedSourceLock = parseObject(storedVisual.sourceLock || {});
const currentSourceLock = Object.keys(sourceLockFromAnalysis).length > 0
  ? sourceLockFromAnalysis
  : storedSourceLock;

// FIX 3.4: Wenn canonical Source-Lock fehlt oder ungültig -> blockieren, kein Prompt
// Keine Ableitung aus Titel, Thema oder satireThemaKonkret
{
  const slPresent = !!(currentSourceLock && currentSourceLock.sourceTopic && currentSourceLock.sourceConflict);
  const slValid = slPresent && (() => {
    try {
      const rawAJ = raw.analysisJson;
      let aj = {};
      if (rawAJ && typeof rawAJ === 'object') aj = rawAJ;
      else if (rawAJ) aj = JSON.parse(String(rawAJ));
      return aj.sourceLockValid === true || String(aj.sourceLockValid||'').trim() === 'true';
    } catch(e) { return false; }
  })();
  if (!slPresent || !slValid) {
    const reason = !slPresent
      ? 'blocked_by_source_lock: canonical Source-Lock fehlt (sourceTopic/sourceConflict)'
      : 'blocked_by_source_lock: analysisJson.sourceLockValid ist nicht true';
    return [{
      json: {
        ...raw,
        visualParseError: false,
        visualDebugReason: reason,
        visualJson: '{}',
        imagePrompt: '',
        imageNegativePrompt: '',
        imageHeadline: '',
        imageSubline: '',
        imageSmallNote: '',
        altText: '',
        imagePromptFound: false,
        visualStatus: 'blocked_by_source_lock',
        visualPromptCreatedAt: new Date().toISOString()
      }
    }];
  }
}


const j = {
  ...raw,

  // Felder, für die keine eigenen Tabellenspalten existieren
  kernbotschaft: firstValue(raw.kernbotschaft, analysis.kernbotschaft),
  dieParteiReaktion: firstValue(raw.dieParteiReaktion, analysis.dieParteiReaktion),

  satireThemaKonkret: firstValue(
    analysisAnchors.satireThemaKonkret,
    analysis.satireThemaKonkret,
    raw.satireThemaKonkret,
    storedAnchors.satireThemaKonkret
  ),
  satireKonfliktKonkret: firstValue(
    analysisAnchors.satireKonfliktKonkret,
    analysis.satireKonfliktKonkret,
    raw.satireKonfliktKonkret,
    storedAnchors.satireKonfliktKonkret
  ),
  visualPflichtobjekte: firstValue(
    analysisAnchors.visualPflichtobjekte,
    analysis.visualPflichtobjekte,
    raw.visualPflichtobjekte,
    storedAnchors.visualPflichtobjekte,
    []
  ),
  visualPflichthandlung: firstValue(
    analysisAnchors.visualPflichthandlung,
    analysis.visualPflichthandlung,
    raw.visualPflichthandlung,
    storedAnchors.visualPflichthandlung
  ),
  visualBetroffene: firstValue(
    analysisAnchors.visualBetroffene,
    analysis.visualBetroffene,
    raw.visualBetroffene,
    storedAnchors.visualBetroffene,
    []
  ),
  visualOrt: firstValue(
    analysisAnchors.visualOrt,
    analysis.visualOrt,
    raw.visualOrt,
    storedAnchors.visualOrt
  ),
  visualUeberzeichnung: firstValue(
    analysisAnchors.visualUeberzeichnung,
    analysis.visualUeberzeichnung,
    raw.visualUeberzeichnung,
    storedAnchors.visualUeberzeichnung
  ),
  visualErkennungssatz: firstValue(
    analysisAnchors.visualErkennungssatz,
    analysis.visualErkennungssatz,
    raw.visualErkennungssatz,
    storedAnchors.visualErkennungssatz
  ),
  visualVerboteneErsatzmotive: firstValue(
    analysisAnchors.visualVerboteneErsatzmotive,
    analysis.visualVerboteneErsatzmotive,
    raw.visualVerboteneErsatzmotive,
    storedAnchors.visualVerboteneErsatzmotive,
    []
  )
};

function isOldMaskPrompt(p) {
  const lower = safeStr(p).toLowerCase();
  return (
    lower.includes('maske') ||
    lower.includes('bearbeite ausschließlich') ||
    lower.includes('editierbaren bereich') ||
    lower.includes('setze die headline') ||
    lower.includes('setze die parteireaktion') ||
    lower.includes('verändere keinen rahmen') ||
    lower.includes('qr-code')
  );
}

// Skip-Prüfung: nur überspringen wenn ALLE neuen Ankerfelder vorhanden sind
function hasValidExistingPrompt(j) {
  const p = safeStr(j.imagePrompt);
  const headline = safeStr(j.imageHeadline);
  const subline = safeStr(j.imageSubline);

  if (p.length < 80) return false;
  if (!headline || !subline) return false;
  if (isOldMaskPrompt(p)) return false;

  // Neue Pflicht: visualJson muss topicPlain + mustShow enthalten
  let vj = null;
  try { vj = JSON.parse(j.visualJson || '{}'); } catch(e) { return false; }
  if (!vj.topicPlain || !vj.conflictPlain) return false;
  if (!Array.isArray(vj.mustShow) || vj.mustShow.length < 2) return false;
  if (!vj.visibleAction || !vj.whyRecognizableWithoutText) return false;
  if (!vj.recognitionSentence) return false;
  if (!vj.forbiddenSubstitutes || !Array.isArray(vj.forbiddenSubstitutes)) return false;

  // FIX 8: forbiddenSubstitutes muss alle aktuellen verbotenen Ersatzmotive abdecken
  let baseVerboten = [];
  try { baseVerboten = JSON.parse(j.visualVerboteneErsatzmotive || '[]'); } catch(e) {}
  if (baseVerboten.length > 0) {
    const notCovered = baseVerboten.filter(bv =>
      !vj.forbiddenSubstitutes.some(fs => skipMatch(bv, fs))
    );
    if (notCovered.length > 0) return false; // verbotene Motive nicht abgedeckt
  }

  // Inhaltlicher Abgleich: mustShow muss visualPflichtobjekte berücksichtigen
  function normSkip(s) {
    return String(s || '').toLowerCase()
      .replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue').replace(/ß/g,'ss');
  }
  function tokensSkip(s) {
    return normSkip(s).split(/[\W]+/).filter(w => w.length >= 4);
  }
  function skipMatch(a, b) {
    const ta = tokensSkip(a), tb = tokensSkip(b);
    if (ta.some(t => tb.includes(t))) return true;
    const na = normSkip(a).replace(/\s+/g,''), nb = normSkip(b).replace(/\s+/g,'');
    return (na.length >= 5 && nb.includes(na)) || (nb.length >= 5 && na.includes(nb));
  }

  let basePflicht = [];
  try { basePflicht = JSON.parse(j.visualPflichtobjekte || '[]'); } catch(e) {}
  if (basePflicht.length >= 2) {
    const matchedPflicht = basePflicht.filter(bp => vj.mustShow.some(ms => skipMatch(bp, ms)));
    if (matchedPflicht.length < 2) return false; // mustShow stimmt nicht mit Pflichtobjekten überein
  }

  // visibleAction muss visualPflichthandlung entsprechen
  const basePflichthandlung = safeStr(j.visualPflichthandlung);
  if (basePflichthandlung && !skipMatch(vj.visibleAction, basePflichthandlung)) return false;

  // recognitionSentence muss visualErkennungssatz entsprechen
  const baseErkennungssatz = safeStr(j.visualErkennungssatz);
  if (baseErkennungssatz && !skipMatch(vj.recognitionSentence, baseErkennungssatz)) return false;

  // imagePrompt muss Pflichthandlung beschreiben
  if (basePflichthandlung && !skipMatch(p, basePflichthandlung)) return false;

  // imagePrompt muss mindestens 2 konkrete Pflichtobjekte enthalten
  if (basePflicht.length >= 2) {
    const promptObjekte = basePflicht.filter(bp => skipMatch(p, bp));
    if (promptObjekte.length < 2) return false;
  }

  // SOURCELOCK-PRÜFUNG: Wenn analysisJson.sourceLock vorhanden, muss bestehendes visualJson damit übereinstimmen
  if (currentSourceLock && currentSourceLock.sourceTopic) {
    function normSL(s) {
      return String(s || '').toLowerCase()
        .replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue').replace(/ß/g,'ss')
        .replace(/[\W]+/g,' ').trim();
    }
    function matchSL(a, b) {
      const ta = normSL(a).split(/\s+/).filter(w => w.length >= 4);
      const tb = normSL(b).split(/\s+/).filter(w => w.length >= 4);
      if (ta.length === 0 || tb.length === 0) return false;
      return ta.some(t => tb.includes(t));
    }
    // topicPlain muss sourceTopic entsprechen
    if (vj.topicPlain && !matchSL(vj.topicPlain, currentSourceLock.sourceTopic)) return false;
    // conflictPlain muss sourceConflict entsprechen
    if (currentSourceLock.sourceConflict && vj.conflictPlain && !matchSL(vj.conflictPlain, currentSourceLock.sourceConflict)) return false;
    // imagePrompt muss mindestens einen konkreten requiredTerm enthalten
    const GENERIC = new Set(['verwaltung','politik','buerokratie','goslar','rathaus','stadt']);
    const reqTerms = (currentSourceLock.requiredTerms || []).filter(t => {
      const tn = normSL(t).replace(/\s/g,'');
      return t.length >= 4 && !GENERIC.has(normSL(t));
    });
    if (reqTerms.length >= 2) {
      const stem = t => normSL(t).substring(0, Math.max(4, Math.floor(normSL(t).length * 0.75)));
      const pNorm = normSL(p);
      const promptHasTerm = reqTerms.some(t => pNorm.includes(stem(t)));
      if (!promptHasTerm) return false;
    }
    // Rein allgemeines topicPlain ist ungültig
    const genericTopics = ['verwaltung','politik','buerokratie','goslar','rathaus','kommunalpolitik'];
    if (genericTopics.includes(normSL(vj.topicPlain))) return false;
  }

  return true;
}

const vorgangKey = safeStr(j.vorgangKey);

if (!vorgangKey) {
  throw new Error(
    'Prepare Visual Prompt Input abgebrochen: vorgangKey fehlt im Eingangsdatenbestand.'
  );
}

// Wenn bereits ein vollständig gültiger Motivprompt + visualJson vorhanden ist: überspringen
if (j._forceVisualPromptReset !== true && hasValidExistingPrompt(j)) {
  return [{
    json: {
      ...j,
      _skipReason: 'valid new motif imagePrompt already exists (incl. visualJson anchor fields)',
      visualStatus: 'visual_prompt_ready',
      imagePromptFound: true,
      visualParseError: false
    }
  }];
}

// Neue Ankerfelder sicher lesen
const satireThemaKonkret       = safeStr(j.satireThemaKonkret);
const satireKonfliktKonkret    = safeStr(j.satireKonfliktKonkret);
const visualPflichtobjekte     = safeJson(j.visualPflichtobjekte, '[]');
const visualPflichthandlung    = safeStr(j.visualPflichthandlung);
const visualBetroffene         = safeJson(j.visualBetroffene, '[]');
const visualOrt                = safeStr(j.visualOrt);
const visualUeberzeichnung     = safeStr(j.visualUeberzeichnung);
const visualErkennungssatz     = safeStr(j.visualErkennungssatz);
const visualVerboteneErsatzmotive = safeJson(j.visualVerboteneErsatzmotive, '[]');

// Sachliche Felder
const summaryText  = safeStr(j.summaryText);
const thema        = safeStr(j.thema);
const betroffene   = safeStr(j.betroffene);
const buergerwirkung = safeStr(j.buergerwirkung);

// KI soll neuen Motivprompt erzeugen
// FIX: imageHeadline/imageSubline aus raw übernehmen statt zu leeren - sonst
// kann "IF Headline bereits gewählt?" weiter unten nie erkennen, dass für
// headline_selected-Zeilen bereits eine Nutzer-Auswahl vorliegt.
const chosenImageHeadline = safeStr(raw.imageHeadline);
const chosenImageSubline  = safeStr(raw.imageSubline);

return [{
  json: {
    vorgangKey,
    vorgangsnummer:          safeStr(j.vorgangsnummer),
    title:                   safeStr(j.title),
    allrisUrl:               safeStr(j.allrisUrl),
    sourceUrl:               safeStr(j.sourceUrl),
    nextcloudFolder:         safeStr(j.nextcloudFolder),

    sprengstoff:             safeStr(j.sprengstoff),
    empfehlung:              safeStr(j.empfehlung),
    relevantScore:           j.relevantScore || 0,
    kommunikationspotenzial: j.kommunikationspotenzial || 0,
    visualDecisionReason:    safeStr(j.visualDecisionReason),

    // Sachliche Zusammenfassung (muss erhalten bleiben)
    summaryText,
    thema,
    betroffene,
    buergerwirkung,

    kernbotschaft:           safeStr(j.kernbotschaft),
    satireBrief:             safeStr(j.satireBrief),
    satireAngle:             safeStr(j.satireAngle),
    satirePunchlines:        safeJson(j.satirePunchlines, '[]'),
    visualMetaphor:          safeStr(j.visualMetaphor),
    satireTarget:            safeStr(j.satireTarget),
    satireIntensity:         Number(j.satireIntensity || 0),
    satireDoNotClaim:        safeJson(j.satireDoNotClaim, '[]'),
    satireSafetyNote:        safeStr(j.satireSafetyNote),
    dieParteiReaktion:       safeStr(j.dieParteiReaktion),
    instagramCaption:        safeStr(j.instagramCaption),
    headlines:               safeStr(j.headlines),
    websiteHeadline:         safeStr(j.websiteHeadline),

    belegbareFakten:         safeJson(j.belegbareFakten, '[]'),
    kritischeNachfrage:      safeStr(j.kritischeNachfrage),
    offenePunkte:            safeJson(j.offenePunkte, '[]'),
    unsicherheitenSummary:   safeStr(j.unsicherheitenSummary),
    analysisJson:            safeJson(j.analysisJson),
    contentJson:             safeJson(j.contentJson),

    // Visuelle Ankerfelder (Pflicht für KI-Prompt)
    satireThemaKonkret,
    satireKonfliktKonkret,
    visualPflichtobjekte,
    visualPflichthandlung,
    visualBetroffene,
    visualOrt,
    visualUeberzeichnung,
    visualErkennungssatz,
    visualVerboteneErsatzmotive,

    imagePrompt:             '',
    imageNegativePrompt:     '',
    imageHeadline:           chosenImageHeadline,
    imageSubline:            chosenImageSubline,
    imageSmallNote:          '',
    altText:                 '',
    visualJson:              '{}',

    _skipReason:             '',
    imagePromptFound:        false,
    visualParseError:        false,
    visualStatus:            'needs_visual_prompt',
    _forceVisualPromptReset: j._forceVisualPromptReset === true,
    _forceVisualPromptResetAt: safeStr(j._forceVisualPromptResetAt),
    _forceVisualPromptResetReason: safeStr(j._forceVisualPromptResetReason),
    sourceLockJson:          JSON.stringify(currentSourceLock || {})
  }
}];

// ============================================================
// PARSE HEADLINE VARIANTEN
// Erwartet { candidates: [{code, imageHeadline, imageSubline}, ...] }
// Speichert Kandidaten in visualJson.headlineCandidates (kein neues DB-Feld
// nötig, gleiches Muster wie sourceLock/anchors) und baut die Matrix-Nachricht.
// ============================================================

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

function extractJson(text) {
  if (!text) return null;
  const stripped = String(text).replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  return stripped.slice(start, end + 1);
}

function getAiText(item) {
  const j = item.json || {};
  if (j.output && Array.isArray(j.output) && j.output[0]?.content?.[0]?.text) return j.output[0].content[0].text;
  if (j.message?.content) return j.message.content;
  if (typeof j.text === 'string' && j.text) return j.text;
  if (Array.isArray(j.choices) && j.choices[0]?.message?.content) return j.choices[0].message.content;
  if (Array.isArray(j.content) && j.content[0]?.text) return j.content[0].text;
  return '';
}

const item = $input.item;
const base = $('Prepare Visual Prompt Input').itemMatching(0).json || {};

const rawText = getAiText(item);
const jsonStr = extractJson(rawText);

let parsed = null;
let parseError = false;
let debugReason = '';

if (!jsonStr) {
  parseError = true;
  debugReason = 'Kein JSON-Block im AI-Output gefunden (Headline-Varianten)';
} else {
  try { parsed = JSON.parse(jsonStr); } catch (e) { parseError = true; debugReason = 'JSON.parse fehlgeschlagen (Headline-Varianten): ' + e.message; }
}

const vnCode = safeStr(base.vorgangsnummer).replace(/[^0-9A-Za-z]+/g, '-').replace(/^-+|-+$/g, '');
const candidates = Array.isArray(parsed && parsed.candidates) ? parsed.candidates : [];
const validCandidates = candidates
  .map(c => ({ code: (vnCode ? vnCode + '-' : '') + safeStr(c && c.code).replace(/^Sat/i, 'K'), imageHeadline: safeStr(c && c.imageHeadline), imageSubline: safeStr(c && c.imageSubline) }))
  .filter(c => c.code && c.imageHeadline && c.imageSubline);

if (!parseError && validCandidates.length < 2) {
  parseError = true;
  debugReason = 'Zu wenige gültige Headline-Kandidaten (' + validCandidates.length + ')';
}

if (!base.vorgangKey) {
  throw new Error('Parse Headline Varianten abgebrochen: vorgangKey fehlt im Ursprungskontext.');
}

if (parseError) {
  return [{
    json: {
      ...base,
      visualParseError: true,
      visualDebugReason: debugReason,
      rawVisualText: (rawText || '(leer)').substring(0, 5000),
      visualStatus: 'visual_prompt_error',
      visualPromptCreatedAt: new Date().toISOString()
    }
  }];
}

let existingVisual = {};
try { existingVisual = typeof base.visualJson === 'string' ? JSON.parse(base.visualJson || '{}') : (base.visualJson || {}); } catch (e) { existingVisual = {}; }

const postedAt = new Date().toISOString();

const lines = [
  '🎨 Bildvorschläge für ' + safeStr(base.vorgangsnummer) + ' – ' + safeStr(base.title),
  ''
];
for (const c of validCandidates) {
  lines.push(c.code + ': ' + c.imageHeadline + ' – ' + c.imageSubline);
}
lines.push('');
const exampleCode = validCandidates.length > 0 ? validCandidates[0].code : ((vnCode ? vnCode + '-' : '') + 'K1');
lines.push('Antworte mit dem gewünschten Code (z.B. "' + exampleCode + '"), um die Auswahl zu bestätigen, oder mit "' + vnCode + '-X" für komplett neue Vorschläge.');

const matrixMessage = lines.join('\n');
const txnId = 'hdl_' + Date.now() + '_' + safeStr(base.vorgangKey).replace(/[^a-zA-Z0-9]/g, '').substring(0, 10);

return [{
  json: {
    ...base,
    visualJson: JSON.stringify({ ...existingVisual, headlineCandidates: validCandidates, candidatesPostedAt: postedAt }),
    visualStatus: 'awaiting_headline_choice',
    visualParseError: false,
    visualDebugReason: '',
    matrixMessage,
    txnId
  }
}];

// Stellt den Vorgangskontext nach dem Matrix-Versand wieder her.
// "Send Matrix Headline Vorschläge" (HTTP Request) ersetzt das Item-JSON durch
// die rohe Matrix-API-Antwort (nur event_id/error) und wirft dabei vorgangKey,
// visualStatus, visualJson, imageHeadline usw. weg. Ohne diesen Node findet
// "Update allris_vorgaenge" keine passende Zeile (vorgangKey=undefined) und
// schreibt gar nichts - der ganze Headline-Auswahl-Fortschritt ging dadurch
// bisher stillschweigend verloren. Gleiches Muster wie "Check Matrix Status" in P1.

const response = $input.item.json || {};
const base = $('Parse Headline Varianten').itemMatching(0).json || {};

const hasError = !!(
  response.error ||
  response.errcode ||
  (response.statusCode && Number(response.statusCode) >= 400)
);
const eventId = response.event_id || response.eventId || '';

return [{
  json: {
    ...base,
    visualStage: (function(vs){ const VD={no_visual:'not_applicable',visual_topic_ok:'topic_ok',visual_topic_error:'topic_error',needs_visual_prompt:'needs_prompt',visual_prompt_ready:'prompt_ready',visual_prompt_error:'prompt_error',visual_prompt_topic_error:'prompt_error',awaiting_headline_choice:'awaiting_headline_choice',headline_selected:'headline_selected',blocked_by_source_lock:'blocked_source_lock',blocked_by_content_error:'blocked_content_error' }; return VD[vs]||(vs?'unknown':'not_applicable'); })(base.visualStatus),
    imageStage: base.imageFinalPath ? 'composed' : 'not_started',
    matrixEventId: eventId,
    matrixSentOk: !hasError && !!eventId,
    matrixSendError: hasError ? (response.error || response.errcode || 'Matrix-Versand fehlgeschlagen') : ''
  }
}];

// ============================================================
// PARSE VISUAL JSON ROBUST  (v2 — visualJson anchor field validation)
// Wichtig: Ursprungskontext aus Prepare Visual Prompt Input behalten
// ============================================================

function extractJson(text) {
  if (!text) return null;
  let s = String(text)
    .replace(/^```(?:json)?\s*/im, '')
    .replace(/\s*```\s*$/m, '')
    .trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  if (start === -1 || end === -1 || end < start) return null;
  return s.slice(start, end + 1);
}

function getAiText(item) {
  const j = item.json || {};
  if (j.output && Array.isArray(j.output) && j.output[0]?.content?.[0]?.text) {
    return j.output[0].content[0].text;
  }
  if (j.message?.content) return j.message.content;
  if (typeof j.text === 'string' && j.text) return j.text;
  if (Array.isArray(j.choices) && j.choices[0]?.message?.content) {
    return j.choices[0].message.content;
  }
  if (Array.isArray(j.content) && j.content[0]?.text) {
    return j.content[0].text;
  }
  return '';
}

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function isOldMaskPrompt(p) {
  const lower = safeStr(p).toLowerCase();
  return (
    lower.includes('maske') ||
    lower.includes('bearbeite ausschließlich') ||
    lower.includes('editierbaren bereich') ||
    lower.includes('setze die headline') ||
    lower.includes('setze die parteireaktion') ||
    lower.includes('verändere keinen rahmen') ||
    lower.includes('qr-code')
  );
}

// Prüft ob imagePrompt hauptsächlich aus allgemeinen Begriffen besteht
// und dabei die konkreten Pflichtobjekte fehlen
function isGenericPrompt(imagePrompt, pflichtobjekte) {
  const lower = safeStr(imagePrompt).toLowerCase();
  const genericTerms = ['satirisch', 'rathaus', 'akten', 'bürokratie', 'chaos',
    'waage', 'labyrinth', 'politik', 'verwaltung', 'allgemein'];

  // Prüfe ob mindestens 2 Pflichtobjekte im Prompt vorkommen
  if (!Array.isArray(pflichtobjekte) || pflichtobjekte.length === 0) return false;
  const foundPflicht = pflichtobjekte.filter(obj =>
    lower.includes(safeStr(obj).toLowerCase().substring(0, 5))
  );
  // Wenn weniger als 2 Pflichtobjekte im Prompt vorkommen UND
  // mehr als 3 allgemeine Begriffe dominieren → als generisch markieren
  const genericCount = genericTerms.filter(t => lower.includes(t)).length;
  return foundPflicht.length < 2 && genericCount > 3;
}

const item = $input.item;
const base = $('Prepare Visual Prompt Input').itemMatching(0).json || {};

const rawText = getAiText(item);
const jsonStr = extractJson(rawText);

let visual = null;
let parseError = false;
let debugReason = '';

if (!jsonStr) {
  parseError = true;
  debugReason = 'Kein JSON-Block im AI-Output gefunden';
} else {
  try {
    visual = JSON.parse(jsonStr);
  } catch (e) {
    parseError = true;
    debugReason = 'JSON.parse fehlgeschlagen: ' + e.message;
