const imagePrompt = safeStr(visual.imagePrompt);
let imageNegativePrompt = safeStr(visual.imageNegativePrompt);

let visualJsonStr = '{}';
let vj = {};
try {
  if (visual.visualJson && typeof visual.visualJson === 'object') {
