// ============================================================
// FIX 3.1: CANONICAL SOURCE-LOCK – analysisJson.sourceLock hat IMMER Vorrang
// KI-generierter sourceLock wird IMMER überschrieben
// visualJson.sourceLock ist ausschließlich eine identische Kopie von analysisJson.sourceLock
// ============================================================
(function enforceCanonicalSourceLock() {
  try {
    // 1. Canonical Source-Lock aus analysisJson lesen
    const rawAnalysis = base.analysisJson;
    let aj = {};
    if (rawAnalysis) {
      if (typeof rawAnalysis === 'object' && !Array.isArray(rawAnalysis)) {
        aj = rawAnalysis;
      } else {
        try { aj = JSON.parse(String(rawAnalysis)); } catch(e) {}
      }
    }
    const canonicalSL = (aj.sourceLock && typeof aj.sourceLock === 'object') ? aj.sourceLock : null;
    const slValid = aj.sourceLockValid === true || String(aj.sourceLockValid || '').trim() === 'true';

    if (!canonicalSL || !canonicalSL.sourceTopic) {
      // Kein canonical Source-Lock: Fehler zurückgeben, KEIN KI-Source-Lock verwenden
      // Das Fehler-Handling erfolgt im nächsten Schritt unten
      vj._canonicalSourceLockMissing = true;
      vj._canonicalSourceLockError = 'analysisJson.sourceLock fehlt oder enthält kein sourceTopic';
      visualJsonStr = JSON.stringify(vj);
      return;
    }

    if (!slValid) {
      vj._canonicalSourceLockMissing = true;
      vj._canonicalSourceLockError = 'analysisJson.sourceLockValid ist nicht true';
      visualJsonStr = JSON.stringify(vj);
      return;
    }

    // 2. KI-generierten sourceLock IMMER mit canonicalSL überschreiben
    vj.sourceLock = canonicalSL;
    visualJsonStr = JSON.stringify(vj);
  } catch (err) {
    vj._canonicalSourceLockError = 'Fehler beim Lesen von analysisJson.sourceLock: ' + String(err);
    visualJsonStr = JSON.stringify(vj);
  }
})();

// Wenn canonical Source-Lock fehlt oder ungültig: Fehler statt Freigabe
if (vj._canonicalSourceLockMissing) {
