if (!safeStr(vj.satireRecognitionSentence)) vjErrors.push('visualJson.satireRecognitionSentence fehlt');
if (!safeStr(vj.whySatiricalWithoutText)) vjErrors.push('visualJson.whySatiricalWithoutText fehlt');

const mustShow = vj.mustShow;
if (!Array.isArray(mustShow) || mustShow.length < 2) {
  vjErrors.push('visualJson.mustShow muss mindestens 2 Elemente enthalten (hat: ' +
    (Array.isArray(mustShow) ? mustShow.length : 0) + ')');
}

// Pflichtobjekte aus base
let basePflichtobjekte = [];
try { basePflichtobjekte = JSON.parse(base.visualPflichtobjekte || '[]'); } catch(e) {}
const basePflichthandlung = safeStr(base.visualPflichthandlung);
const baseErkennungssatz  = safeStr(base.visualErkennungssatz);
let baseVerbotene = [];
try { baseVerbotene = JSON.parse(base.visualVerboteneErsatzmotive || '[]'); } catch(e) {}

