}

// Inhaltsabgleich: mustShow muss die Pflichtobjekte berücksichtigen
// (mind. 2 Überschneidungen zwischen mustShow und basePflichtobjekte)
function normalizeGerman(s) {
  // Umlautnormalisierung + Kleinschreibung
  return safeStr(s).toLowerCase()
    .replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue')
    .replace(/ß/g,'ss');
}

function stemLight(w) {
  // Leichtes Stemming: häufige deutsche Endungen entfernen
  return w
    .replace(/(ungen|ierung|ierung|ungen|heit|keit|schaft|tion|ieren|iere|iert|ung|lich|lich|isch|ische|ischen|ischer|isches)$/, '')
    .replace(/(en|er|em|es|e|n|s|t)$/, '');
}

function tokenOverlap(a, b) {
  // Robuster Vergleich für deutsche Komposita:
  // 1. Exakter Wortvergleich nach Normalisierung
  // 2. Stemming
  // 3. Teilwortvergleich (ab 5 Zeichen Mindestlänge)
  const norm = (s) => normalizeGerman(s);
  const tokensA = norm(a).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  const tokensB = norm(b).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);

  // Exakter Treffer nach Normalisierung
  if (tokensA.some(w => tokensB.includes(w))) return true;

  // Teilwortvergleich: Kompositum enthält den anderen Begriff?
  const rawA = norm(a).replace(/[\W_]+/g, '');
  const rawB = norm(b).replace(/[\W_]+/g, '');

  // Mindestens 5 Zeichen für Teilwortvergleich
  for (const tok of tokensA) {
    if (tok.length >= 5 && rawB.includes(tok)) return true;
  }
  for (const tok of tokensB) {
    if (tok.length >= 5 && rawA.includes(tok)) return true;
  }

  return false;
}

if (Array.isArray(mustShow) && mustShow.length >= 2 && basePflichtobjekte.length >= 2) {
  const matches = mustShow.filter(ms =>
    basePflichtobjekte.some(bp => tokenOverlap(ms, bp))
  );
  if (matches.length < 2) {
    vjErrors.push(
      'visualJson.mustShow stimmt nicht mit visualPflichtobjekte überein. ' +
      'mustShow: [' + mustShow.slice(0,3).join(', ') + '] vs. ' +
      'Pflicht: [' + basePflichtobjekte.slice(0,3).join(', ') + ']'
    );
  }
}

// visibleAction muss Pflichthandlung inhaltlich entsprechen
if (safeStr(vj.visibleAction) && basePflichthandlung) {
  if (!tokenOverlap(vj.visibleAction, basePflichthandlung)) {
    vjErrors.push(
      'visualJson.visibleAction stimmt nicht mit visualPflichthandlung überein. ' +
      'visibleAction: "' + safeStr(vj.visibleAction).substring(0,80) + '" vs. ' +
      'Pflicht: "' + basePflichthandlung.substring(0,80) + '"'
    );
  }
}

// recognitionSentence muss Erkennungssatz inhaltlich entsprechen
if (safeStr(vj.recognitionSentence) && baseErkennungssatz) {
  if (!tokenOverlap(vj.recognitionSentence, baseErkennungssatz)) {
    vjErrors.push(
      'visualJson.recognitionSentence stimmt nicht mit visualErkennungssatz überein'
    );
  }
}

// imagePrompt muss Pflichthandlung beschreiben
if (basePflichthandlung && imagePrompt) {
  if (!tokenOverlap(imagePrompt, basePflichthandlung)) {
    vjErrors.push(
      'imagePrompt beschreibt visualPflichthandlung nicht sichtbar. ' +
      'Pflichthandlung: "' + basePflichthandlung.substring(0,80) + '"'
    );
  }
}

// imagePrompt darf keinen neuen politischen Nebenkriegsschauplatz eröffnen:
// Prüfe auf politisch aufgeladene Begriffe die nicht aus den Ankerfeldern stammen
const POLITICAL_MARKERS = ['wahl','kandidat','partei','abgeordnete','bürgermeist','stadtrat'];
const anchorText = (basePflichtobjekte.join(' ') + ' ' + basePflichthandlung + ' ' + 
  safeStr(base.satireThemaKonkret)).toLowerCase();
const promptLower = imagePrompt.toLowerCase();
for (const marker of POLITICAL_MARKERS) {
  if (promptLower.includes(marker) && !anchorText.includes(marker)) {
    vjErrors.push('imagePrompt enthält politischen Begriff "' + marker + '" der nicht aus den Ankerfeldern stammt');
    break; // nur erstes Problem melden
  }
}

// Prüfe ob imagePrompt zu generisch ist
if (isGenericPrompt(imagePrompt, basePflichtobjekte)) {
  vjErrors.push('imagePrompt besteht hauptsächlich aus allgemeinen Begriffen; ' +
    'konkrete Pflichtobjekte fehlen im Prompt');
}

if (vjErrors.length > 0) {
  return [{
    json: {
      ...base,
      visualParseError: true,
      visualDebugReason: 'visualJson-Ankerfelder ungültig: ' + vjErrors.join(' | '),
      rawVisualText: (rawText || '(leer)').substring(0, 5000),
      visualJson: visualJsonStr,
      imagePrompt: '',
      imageNegativePrompt,
      imageHeadline,
      imageSubline,
      imageSmallNote,
      altText,
      imagePromptFound: false,
      visualStatus: 'visual_prompt_topic_error',
      visualPromptCreatedAt: new Date().toISOString()
    }
  }];
}

// ============================================================
// ALLES OK
// ============================================================
return [{
  json: {
    ...base,
    imageHeadline,
    imageSubline,
    imageSmallNote,
    altText,
    imagePrompt,
    imageNegativePrompt: imageNegativePrompt || 'text, letters, numbers, typography, logos, coats of arms, seals, QR codes, real people, politicians, fake documents, NSFW, blurry, low contrast, cluttered background',
    visualJson: visualJsonStr,
    imagePromptFound: true,
    visualParseError: false,
    rawVisualText: '',
    visualDebugReason: '',
    visualStatus: 'visual_prompt_ready',
    visualPromptCreatedAt: new Date().toISOString()
  }
}];

