function getRetryInfo(j) {
  let vj = {};
  try {
    vj = JSON.parse(j.visualJson || '{}');
    if (typeof vj !== 'object') vj = {};
  } catch(e) {}
  const wf = (typeof vj.workflow === 'object' && vj.workflow) ? vj.workflow : {};
  const attempt = Math.max(1, Number(wf.visualPromptAttempt || j.visualPromptAttempt || 1));
  const maxAttempts = Math.max(2, Number(wf.visualPromptMaxAttempts || j.visualPromptMaxAttempts || 2));
  return { attempt, maxAttempts, canRetry: attempt < maxAttempts, vj, wf };
}

const j = $input.first().json || {};

function safeStr(v) {
  if (v === null || v === undefined) return "";
  return String(v).trim();
}

function parseMaybeJson(v) {
  if (!v) return {};
  if (typeof v === "object") return v;
  try { return JSON.parse(v); } catch (e) { return {}; }
}

// === Orchestrator-Migration Durchgang A: visualStage/imageStage additiv ===
const VISUAL_DIRECT = { 'no_visual': 'not_applicable', 'visual_topic_ok': 'topic_ok', 'visual_topic_error': 'topic_error', 'blocked_by_content_error': 'blocked_content_error', 'blocked_by_source_lock': 'blocked_source_lock', 'waiting_for_content': 'waiting_for_content', 'needs_visual_prompt': 'needs_prompt', 'visual_prompt_ready': 'prompt_ready', 'visual_prompt_error': 'prompt_error', 'visual_prompt_topic_error': 'prompt_error', 'awaiting_headline_choice': 'awaiting_headline_choice', 'headline_selected': 'headline_selected', 'force_visual_reset': 'needs_prompt', 'visual_prompt_failed_final': 'prompt_failed_final' };
const IMAGE_VALUES_P5 = new Set(['image_composed', 'nextcloud_upload_failed', 'image_retrying', 'retry_required', 'image_qa_error', 'image_quality_failed', 'image_qa_approved', 'visual_concept_repairing', 'visual_concept_repair_failed', 'visual_prompt_ready', 'visual_topic_error_final', 'blocked_by_source_lock', 'image_qa_rechecking', 'force_image_refresh', 'force_image_reset', 'force_full_image_refresh', 'visual_prompt_failed_final', 'image_prompt_ready', 'image_retry_required', 'image_qa_retry_required', 'raw_generated', 'ready_for_composite']);
const IMAGE_DIRECT_P5 = { 'raw_generated': 'raw_generated', 'ready_for_composite': 'ready_for_composite', 'image_composed': 'composed', 'nextcloud_upload_failed': 'upload_failed', 'image_retrying': 'qa_pending', 'retry_required': 'qa_pending', 'image_retry_required': 'qa_pending', 'image_qa_error': 'qa_pending', 'image_qa_retry_required': 'qa_pending', 'image_qa_rechecking': 'qa_pending', 'image_quality_failed': 'qa_failed', 'image_qa_approved': 'qa_approved', 'visual_concept_repairing': 'concept_repairing', 'visual_concept_repair_failed': 'concept_repair_failed', 'visual_topic_error_final': 'topic_error_final' };
function mapVisualStage(visualStatusValue) {
  const vs = safeStr(visualStatusValue);
  if (Object.prototype.hasOwnProperty.call(VISUAL_DIRECT, vs)) return VISUAL_DIRECT[vs];
  if (IMAGE_VALUES_P5.has(vs)) return 'prompt_ready';
  if (vs === '') return 'not_applicable';
  return 'unknown';
}
function mapImageStage(visualStatusValue, imageFinalPathValue) {
  const vs = safeStr(visualStatusValue);
  if (Object.prototype.hasOwnProperty.call(IMAGE_DIRECT_P5, vs)) return IMAGE_DIRECT_P5[vs];
  if (safeStr(imageFinalPathValue)) return 'composed';
  return 'not_started';
}

// FIX 1.4: blocked_by_source_lock pass-through — kein KI-Aufruf, keine Pflichtfelder
if (safeStr(j.visualStatus) === 'blocked_by_source_lock') {
  return [{
    json: {
      ...j,
      visualStatus: 'blocked_by_source_lock',
      visualStage: mapVisualStage('blocked_by_source_lock'),
      imageStage: mapImageStage('blocked_by_source_lock', j.imageFinalPath),
      status: j.status || 'blocked_by_source_lock'
    }
  }];
}

// FIX 1.1: Retry-Zähler hier erhöhen, BEVOR Update allris_vorgaenge läuft
const errorStatuses = new Set(['visual_prompt_error', 'visual_prompt_topic_error']);
if (errorStatuses.has(safeStr(j.visualStatus))) {
  const { attempt, maxAttempts, vj, wf } = getRetryInfo(j);
  const newAttempt = attempt + 1;
  if (newAttempt > maxAttempts) {
    vj.workflow = { ...wf, visualPromptAttempt: newAttempt, visualPromptMaxAttempts: maxAttempts, visualPromptFinalStatus: 'visual_prompt_failed_final' };
    return [{
      json: {
        ...j,
        visualJson: JSON.stringify(vj),
        visualStatus: 'visual_prompt_failed_final',
        visualPromptAttempt: newAttempt,
        visualPromptMaxAttempts: maxAttempts,
        visualStage: mapVisualStage('visual_prompt_failed_final'),
