// FIX 10: Prüfe Content-Abschluss - vollständige Prüfung (V3_11)
const j = $input.item.json || {};
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; } catch(e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(s => String(s).trim());
  if (typeof v === 'string' && v.trim()) {
    try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(s => String(s).trim()); } catch(e) {}
  }
  return [];
}
function robustBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') { const s = v.trim().toLowerCase(); return s === 'true' || s === '1'; }
  return false;
}

const visualStatus = safeStr(j.visualStatus);
const status = safeStr(j.status);
const forceVisualPromptReset = j._forceVisualPromptReset === true || j.visualForceReset === true || visualStatus === 'force_visual_reset';

const errors = [];

// 1. visualStatus muss needs_visual_prompt oder retry-Status sein
const contentStage = safeStr(j.contentStage);
const contentStageOk = contentStage
  ? (contentStage === 'content_generated' || contentStage === 'content_posted')
  : (status === 'content_generated' || status === 'content_posted');
const contentStatusOk = contentStageOk || forceVisualPromptReset;
if (!contentStatusOk) errors.push('status nicht content_generated/content_posted und kein Force-Reset (ist: ' + status + ')');

// 2. contentJson muss vorhanden sein
const contentJson = parseObj(j.contentJson);
const contentPresent = !!(safeStr(j.websiteHeadline) || Object.keys(contentJson).length > 0);
if (!contentPresent) errors.push('contentJson fehlt oder leer');

// 3. sourceLockValid
const analysis = parseObj(j.analysisJson);
const slValidFlag = robustBool(analysis.sourceLockValid);
if (!slValidFlag) errors.push('sourceLockValid nicht true');

// 4. sourceLock vollständig (FIX 10: inkl. requiredObjects + requiredAction)
const sl = parseObj(analysis.sourceLock || {});
const slComplete = !!(
  safeStr(sl.sourceTopic) && safeStr(sl.sourceConflict) &&
  asArr(sl.requiredTerms).length >= 2 &&
  asArr(sl.requiredObjects).length >= 2 &&
  safeStr(sl.requiredAction) &&
  slValidFlag
);
if (!slComplete) errors.push('sourceLock unvollständig (requiredObjects/requiredAction prüfen)');

// 5. visualAnchors vollständig (FIX 10: inkl. visualVerboteneErsatzmotive >= 2 + visualAnchorsValid)
const vaValidFlag = robustBool(analysis.visualAnchorsValid);
const va = parseObj(analysis.visualAnchors || {});
const vaComplete = !!(
  safeStr(va.satireThemaKonkret) && safeStr(va.satireKonfliktKonkret) &&
  asArr(va.visualPflichtobjekte).length >= 2 &&
  safeStr(va.visualPflichthandlung) && safeStr(va.visualErkennungssatz) &&
  safeStr(va.visualUeberzeichnung) &&
  asArr(va.visualVerboteneErsatzmotive).length >= 2 &&
  vaValidFlag
);
if (!vaComplete) errors.push('visualAnchors unvollständig (visualVerboteneErsatzmotive/visualAnchorsValid prüfen)');

const contentGateOk = errors.length === 0;

return [{
  json: {
    ...j,
    _contentGateOk: contentGateOk,
    _contentGateErrors: errors,
    _contentGateForceReset: forceVisualPromptReset
  }
}];

// Sortierung: 1. firstseen aufsteigend, 2. volfdnr numerisch, 3. vorgangKey lexikografisch
function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}
function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}
const items = $input.all();
items.sort((a, b) => {
  const ja = a.json || {}, jb = b.json || {};
  const fa = parseDate(ja.firstseen), fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;
  const va = parseVolfdnr(ja.volfdnr), vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;
  return String(ja.vorgangKey || '').localeCompare(String(jb.vorgangKey || ''));
});
return items;

// ============================================================
// FORCE VISUAL PROMPT RESET SCHALTER
// Setzt alte Bildprompt-Felder vor der Content-Gate-Prüfung zurück.
// Standard: AUS. Sicherste Nutzung: In der DataTable visualStatus = "force_visual_reset" setzen.
// Optional: FORCE_RESET_VISUAL_PROMPT auf true setzen und mit VorgangKey/Vorgangsnummer begrenzen.
// ============================================================

const FORCE_RESET_VISUAL_PROMPT = false;      // nur kurzzeitig auf true setzen
const FORCE_ONLY_VORGANG_KEY = '';             // z.B. 'vol_10742' oder leer
const FORCE_ONLY_VORGANGSNUMMER = '';          // z.B. '2026/197' oder leer

const j = $input.item.json || {};

function safeStr(v) {
  if (v === null || v === undefined) return '';
  return String(v).trim();
}

function norm(v) {
  return safeStr(v).toLowerCase();
}

const visualStatus = norm(j.visualStatus);
const vorgangKey = safeStr(j.vorgangKey);
const vorgangsnummer = safeStr(j.vorgangsnummer);

const resetByStatus = (j.visualForceReset === true) || visualStatus === 'force_visual_reset';
const hasTarget = !!(safeStr(FORCE_ONLY_VORGANG_KEY) || safeStr(FORCE_ONLY_VORGANGSNUMMER));
const targetMatches =
  (!safeStr(FORCE_ONLY_VORGANG_KEY) || vorgangKey === safeStr(FORCE_ONLY_VORGANG_KEY)) &&
  (!safeStr(FORCE_ONLY_VORGANGSNUMMER) || vorgangsnummer === safeStr(FORCE_ONLY_VORGANGSNUMMER));

// Sicherheitslogik:
// - visualStatus=force_visual_reset setzt immer genau diesen Datensatz zurück.
// - FORCE_RESET_VISUAL_PROMPT=true ohne Ziel setzt nur bereits geholte Kandidaten zurück.
// - Für gezieltes Zurücksetzen per Variable immer FORCE_ONLY_* setzen.
const resetByVariable = FORCE_RESET_VISUAL_PROMPT === true && (!hasTarget || targetMatches);
const doReset = resetByStatus || resetByVariable;

if (!doReset) {
  return [{ json: { ...j, _forceVisualPromptReset: false } }];
}

return [{
  json: {
    ...j,
    _forceVisualPromptReset: true,
    _forceVisualPromptResetAt: new Date().toISOString(),
    _forceVisualPromptResetReason: resetByStatus
      ? 'visualStatus=force_visual_reset'
      : 'FORCE_RESET_VISUAL_PROMPT=true',

    // Wichtig: Status des Visual Prompt Builders wieder öffnen
    visualStatus: 'needs_visual_prompt',

    // Alte Visual-Prompt-Artefakte entfernen, damit kein Skip greifen kann
    imagePrompt: '',
    imageNegativePrompt: '',
    imageHeadline: '',
    imageSubline: '',
    imageSmallNote: '',
    altText: '',
    visualJson: '{}',
    visualParseError: false,
