    imageFinalPath: '',
    imageCreatedAt: '',
    imageWorkflowVersion: '',

    // Interne Hinweise, falls Felder nicht als Spalten existieren: unschädlich im Laufzeit-JSON
    imagePromptFound: false,
    _skipReason: ''
  }
}];
